#include <stdio.h>
int main() {
    int T, N, a, xor;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        xor = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d", &a);
            xor ^= a;
        }
        if (xor == 0) printf("Head Chef\n");
        else printf("Little Chef\n");
    }
    return 0;
}

