    while (T--) {
        cin >> N;
        xor = 0;
        for (int i = 0; i < N; i++) {
            cin >> a;
            xor ^= a;
        }
        if (xor == 0) cout << "Head Chef" << endl;
        else cout << "Little Chef" << endl;
