    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int xor = 0;
            for (int i = 0; i < N; i++) {
                int a = sc.nextInt();
                xor ^= a;
            }
            if (xor == 0) System.out.println("Head Chef");
            else System.out.println("Little Chef");
        }
    }
}

